+option optimize_for = SPEED;
+option cc_enable_arenas = true;
+option java_package = "com.google.protobuf";
+option java_outer_classname = "DescriptorProto";
+option java_multiple_files = true;
+option objc_class_prefix = "GPB";
+option go_package = "google.golang.org/protobuf/types/descriptorpb";
+
+message FileDescriptorSet {
+  repeated FileDescriptorProto file = 1;
+}
+
+message FileDescriptorProto {
+  optional string name = 1;
+  optional string package = 2;
+  repeated string dependency = 3;
+  repeated int32 public_dependency = 10;
+  repeated int32 weak_dependency = 9;
+  repeated DescriptorProto message_type = 4;
+  repeated EnumDescriptorProto enum_type = 5;
+  repeated ServiceDescriptorProto service = 6;
+  repeated FieldDescriptorProto extension = 7;
+  optional ExtensionRangeOptions options = 8;
+  optional SourceCodeInfo source_code_info = 9;
+  optional string syntax = 12;
+}
+
+message DescriptorProto {
+  message ExtensionRange {
+    optional int32 start = 1;
+    optional int32 end = 3;
+    optional ExtensionRangeOptions options = 2;
+  }
+
+  message ReservedRange {
+    optional int32 start = 1;
+    optional int32 end = 2;
+  }
+
+  optional string name = 1;
+  repeated FieldDescriptorProto field = 2;
+  repeated FieldDescriptorProto extension = 6;
+  repeated DescriptorProto nested_type = 3;
+  repeated EnumDescriptorProto enum_type = 4;
+  repeated ExtensionRange extension_range = 5;
+  repeated ReservedRange reserved_range = 9;
+  repeated string reserved_name = 10;
+  optional FieldDescriptorProto oneof_decl = 8;
+  optional EnumValueDescriptorProto enum_value = 7;
+}
+
+message FieldDescriptorProto {
+  enum Type {
+    TYPE_DOUBLE = 1;
+    TYPE_FLOAT = 2;
+    TYPE_INT64 = 3;
+    TYPE_UINT64 = 4;
+    TYPE_INT32 = 5;
+    TYPE_FIXED64 = 6;
+    TYPE_FIXED32 = 7;
+    TYPE_BOOL = 8;
+    TYPE_STRING = 9;
+    TYPE_GROUP = 10;
+    TYPE_MESSAGE = 11;
+    TYPE_BYTES = 12;
+    TYPE_UINT32 = 13;
+    TYPE_ENUM = 14;
+    TYPE_SFIXED32 = 15;
+    TYPE_SFIXED64 = 16;
+    TYPE_SINT32 = 17;
+    TYPE_SINT64 = 18;
+  }
+
+  enum Label {
+    LABEL_OPTIONAL = 1;
+    LABEL_REQUIRED = 2;
+    LABEL_REPEATED = 3;
+  }
+
+  optional string name = 1;
+  optional int32 number = 3;
+  optional Label label = 4;
+  optional Type type = 5;
+  optional string type_name = 9;
+  optional string default_value = 10;
+  optional bool default_bool = 20;
+  optional int32 default_int32 = 21;
+  optional int64 default_int64 = 22;
+  optional uint32 default_uint32 = 23;
+  optional uint64 default_uint64 = 24;
+  optional float default_float = 25;
+  optional double default_double = 26;
+  optional string default_string = 27;
+  optional bytes default_bytes = 28;
+  optional EnumValueDescriptorProto default_enum = 29;
+  optional int32 type = 6;
+  optional int32 label = 7;
+  optional bool is_extension = 8;
+  optional int32 extendee = 9;
+  optional bool packed = 17;
+  optional bool map_entry = 7;
+  optional string json_name = 10;
+  optional bool jstype = 6;
+  optional bool lazy = 5;
+  optional bool deprecated = 3;
+  optional bool weak = 9;
+  optional string default_value_string = 20;
+  optional string default_value_lithium = 21;
+  optional string default_value_utype = 22;
+  optional string default_value_uinteger = 23;
+  optional
